table inet altura_prot_edge {
	set protected_tcp_ports {
		type inet_service
		elements = { 80, 443, 8080 }
	}

	set tcp4_connlimit {
		type ipv4_addr . inet_service
		size 65535
		flags dynamic
	}

	set tcp6_connlimit {
		type ipv6_addr . inet_service
		size 65535
		flags dynamic
	}

	set tcp4_syn_rate {
		type ipv4_addr . inet_service
		size 65535
		flags dynamic,timeout
		timeout 10s
	}

	set tcp6_syn_rate {
		type ipv6_addr . inet_service
		size 65535
		flags dynamic,timeout
		timeout 10s
	}

	chain preraw {
		type filter hook prerouting priority raw; policy accept;
		tcp dport @protected_tcp_ports tcp flags ! fin,syn,rst,ack drop
		tcp dport @protected_tcp_ports tcp flags & (fin | syn | rst | psh | ack | urg) == fin | psh | urg drop
		udp dport @protected_tcp_ports drop
		ip protocol tcp tcp dport @protected_tcp_ports tcp flags & (fin | syn | rst | ack) == syn update @tcp4_syn_rate { ip saddr . tcp dport limit rate over 200/second burst 400 packets } drop
		tcp dport @protected_tcp_ports tcp flags & (fin | syn | rst | ack) == syn update @tcp6_syn_rate { ip6 saddr & ffff:ffff:ffff:ffff:: . tcp dport limit rate over 200/second burst 400 packets } drop
		tcp dport @protected_tcp_ports tcp flags & (fin | syn | rst | ack) == syn limit rate over 5000/second burst 10000 packets drop
	}

	chain input {
		type filter hook input priority filter; policy accept;
		ct state invalid drop
		tcp dport @protected_tcp_ports ct state new tcp flags & (fin | syn | rst | ack) != syn drop
		ip protocol tcp tcp dport @protected_tcp_ports ct state new add @tcp4_connlimit { ip saddr . tcp dport ct count over 128 } drop
		tcp dport @protected_tcp_ports ct state new add @tcp6_connlimit { ip6 saddr & ffff:ffff:ffff:ffff:: . tcp dport ct count over 128 } drop
		tcp dport @protected_tcp_ports ct state new limit rate over 5000/second burst 10000 packets drop
		ip protocol icmp icmp type { destination-unreachable, time-exceeded, parameter-problem } accept
		ip protocol icmp limit rate over 100/second burst 200 packets drop
		icmpv6 type { destination-unreachable, packet-too-big, time-exceeded, parameter-problem, nd-router-solicit, nd-router-advert, nd-neighbor-solicit, nd-neighbor-advert } accept
		meta l4proto ipv6-icmp limit rate over 100/second burst 200 packets drop
	}
}
